    pub const fn is_disabled(&self) -> bool {
        self.ctx.disabled
    }

    /// Returns whether a specific item is disabled by group or item state.
    #[must_use]
    pub fn is_item_disabled(&self, item_id: &Key) -> bool {
        is_item_disabled(self.ctx, item_id)
    }

