                let target = idle_focus_seed(ctx, FocusStep::Next)?;
                Some(focus_plan(target, true, true))
            }

            (State::Idle, Event::FocusPrev) => {
                let target = idle_focus_seed(ctx, FocusStep::Prev)?;
                Some(focus_plan(target, true, true))
            }

